arguments.command:
cd /tmp/sv-57d295c2a48946fdbe1dd3f0d5c1607f
# Also try to resolve the System.Native frames using the dynamic symbol table approach
# We can look up the addresses in the dynsym table of the monosgen binary for more info
# First let me use nm or readelf to find nearest symbols for each address
for addr in 0x222098 0x222234 0x19bac0 0x19bc14; do
  echo "=== $addr ==="
  readelf -W --dyn-syms libmonosgen-2.0.so 2>/dev/null | awk -v addr="$addr" '
    BEGIN { target = strtonum(addr); best_name=""; best_addr=0; best_size=0 }
    /FUNC/ {
      sym_addr = strtonum("0x" $2);
      sym_size = strtonum($3);
      if (sym_addr <= target && sym_addr > best_addr) {
        best_addr = sym_addr;
        best_name = $8;
        best_size = sym_size;
      }
    }
    END { printf "  %s+0x%x (size=0x%x)\n", best_name, target - best_addr, best_size }
  '
done

